    function ValidateField_valorprevisao_(&$Campos_Crit, &$Campos_Falta, &$Campos_Erros)
    {
        global $teste_validade;
        $hasError = false;
      if (isset($this->Field_no_validate['valorprevisao_'])) {
          if (!empty($this->field_config['valorprevisao_']['symbol_dec'])) {
              $this->sc_remove_currency($this->valorprevisao_, $this->field_config['valorprevisao_']['symbol_dec'], $this->field_config['valorprevisao_']['symbol_grp'], $this->field_config['valorprevisao_']['symbol_mon']); 
              nm_limpa_valor($this->valorprevisao_, $this->field_config['valorprevisao_']['symbol_dec'], $this->field_config['valorprevisao_']['symbol_grp']) ; 
          }
          return;
      }
      if (!empty($this->field_config['valorprevisao_']['symbol_dec']))
      {
          $this->sc_remove_currency($this->valorprevisao_, $this->field_config['valorprevisao_']['symbol_dec'], $this->field_config['valorprevisao_']['symbol_grp'], $this->field_config['valorprevisao_']['symbol_mon']); 
          nm_limpa_valor($this->valorprevisao_, $this->field_config['valorprevisao_']['symbol_dec'], $this->field_config['valorprevisao_']['symbol_grp']) ; 
          if ('.' == substr($this->valorprevisao_, 0, 1))
          {
              if ('' == str_replace('0', '', substr($this->valorprevisao_, 1)))
              {
                  $this->valorprevisao_ = '';
              }
              else
              {
                  $this->valorprevisao_ = '0' . $this->valorprevisao_;
              }
          }
      }
      if ($this->nmgp_opcao != "excluir") 
      { 
          if ($this->valorprevisao_ != '')  
          { 
              $iTestSize = 13;
              if ('-' == substr($this->valorprevisao_, 0, 1))
              {
                  $iTestSize++;
              }
              elseif ('-' == substr($this->valorprevisao_, -1))
              {
                  $iTestSize++;
                  $this->valorprevisao_ = '-' . substr($this->valorprevisao_, 0, -1);
              }
              if (strlen($this->valorprevisao_) > $iTestSize)  
              { 
                  $hasError = true;
                  $Campos_Crit .= "Valor Previsto: " . $this->Ini->Nm_lang['lang_errm_size']; 
                  if (!isset($Campos_Erros['valorprevisao_']))
                  {
                      $Campos_Erros['valorprevisao_'] = array();
                  }
                  $Campos_Erros['valorprevisao_'][] = $this->Ini->Nm_lang['lang_errm_size'];
                  if (!isset($this->NM_ajax_info['errList']['valorprevisao_']) || !is_array($this->NM_ajax_info['errList']['valorprevisao_']))
                  {
                      $this->NM_ajax_info['errList']['valorprevisao_'] = array();
                  }
                  $this->NM_ajax_info['errList']['valorprevisao_'][] = $this->Ini->Nm_lang['lang_errm_size'];
              } 
              if ($teste_validade->Valor($this->valorprevisao_, 10, 2, 0, 0, "S") == false)  
              { 
                  $hasError = true;
                  $Campos_Crit .= "Valor Previsto; " ; 
                  if (!isset($Campos_Erros['valorprevisao_']))
                  {
                      $Campos_Erros['valorprevisao_'] = array();
                  }
                  $Campos_Erros['valorprevisao_'][] = "" . $this->Ini->Nm_lang['lang_errm_ajax_data'] . "";
                  if (!isset($this->NM_ajax_info['errList']['valorprevisao_']) || !is_array($this->NM_ajax_info['errList']['valorprevisao_']))
                  {
                      $this->NM_ajax_info['errList']['valorprevisao_'] = array();
                  }
                  $this->NM_ajax_info['errList']['valorprevisao_'][] = "" . $this->Ini->Nm_lang['lang_errm_ajax_data'] . "";
              } 
          } 
           elseif (!isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['php_cmp_required']['valorprevisao_']) || $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['php_cmp_required']['valorprevisao_'] == "on") 
           { 
