    function ValidateField_valorrealizacao_(&$Campos_Crit, &$Campos_Falta, &$Campos_Erros)
    {
        global $teste_validade;
        $hasError = false;
      if (isset($this->Field_no_validate['valorrealizacao_'])) {
          if (!empty($this->field_config['valorrealizacao_']['symbol_dec'])) {
              $this->sc_remove_currency($this->valorrealizacao_, $this->field_config['valorrealizacao_']['symbol_dec'], $this->field_config['valorrealizacao_']['symbol_grp'], $this->field_config['valorrealizacao_']['symbol_mon']); 
              nm_limpa_valor($this->valorrealizacao_, $this->field_config['valorrealizacao_']['symbol_dec'], $this->field_config['valorrealizacao_']['symbol_grp']) ; 
          }
          return;
      }
      if ($this->valorrealizacao_ === "" || is_null($this->valorrealizacao_))  
      { 
          $this->valorrealizacao_ = 0;
          $this->sc_force_zero[] = 'valorrealizacao_';
      } 
      if (!empty($this->field_config['valorrealizacao_']['symbol_dec']))
      {
          $this->sc_remove_currency($this->valorrealizacao_, $this->field_config['valorrealizacao_']['symbol_dec'], $this->field_config['valorrealizacao_']['symbol_grp'], $this->field_config['valorrealizacao_']['symbol_mon']); 
          nm_limpa_valor($this->valorrealizacao_, $this->field_config['valorrealizacao_']['symbol_dec'], $this->field_config['valorrealizacao_']['symbol_grp']) ; 
          if ('.' == substr($this->valorrealizacao_, 0, 1))
          {
              if ('' == str_replace('0', '', substr($this->valorrealizacao_, 1)))
              {
                  $this->valorrealizacao_ = '';
              }
              else
              {
                  $this->valorrealizacao_ = '0' . $this->valorrealizacao_;
              }
          }
      }
      if ($this->nmgp_opcao != "excluir") 
      { 
          if ($this->valorrealizacao_ != '')  
          { 
              $iTestSize = 13;
              if ('-' == substr($this->valorrealizacao_, 0, 1))
              {
                  $iTestSize++;
              }
              elseif ('-' == substr($this->valorrealizacao_, -1))
              {
                  $iTestSize++;
                  $this->valorrealizacao_ = '-' . substr($this->valorrealizacao_, 0, -1);
              }
              if (strlen($this->valorrealizacao_) > $iTestSize)  
              { 
                  $hasError = true;
                  $Campos_Crit .= "Valor Pago: " . $this->Ini->Nm_lang['lang_errm_size']; 
                  if (!isset($Campos_Erros['valorrealizacao_']))
                  {
                      $Campos_Erros['valorrealizacao_'] = array();
                  }
                  $Campos_Erros['valorrealizacao_'][] = $this->Ini->Nm_lang['lang_errm_size'];
                  if (!isset($this->NM_ajax_info['errList']['valorrealizacao_']) || !is_array($this->NM_ajax_info['errList']['valorrealizacao_']))
                  {
                      $this->NM_ajax_info['errList']['valorrealizacao_'] = array();
                  }
                  $this->NM_ajax_info['errList']['valorrealizacao_'][] = $this->Ini->Nm_lang['lang_errm_size'];
              } 
              if ($teste_validade->Valor($this->valorrealizacao_, 10, 2, 0, 0, "S") == false)  
              { 
                  $hasError = true;
                  $Campos_Crit .= "Valor Pago; " ; 
                  if (!isset($Campos_Erros['valorrealizacao_']))
                  {
                      $Campos_Erros['valorrealizacao_'] = array();
                  }
                  $Campos_Erros['valorrealizacao_'][] = "" . $this->Ini->Nm_lang['lang_errm_ajax_data'] . "";
                  if (!isset($this->NM_ajax_info['errList']['valorrealizacao_']) || !is_array($this->NM_ajax_info['errList']['valorrealizacao_']))
                  {
                      $this->NM_ajax_info['errList']['valorrealizacao_'] = array();
                  }
                  $this->NM_ajax_info['errList']['valorrealizacao_'][] = "" . $this->Ini->Nm_lang['lang_errm_ajax_data'] . "";
              } 
          } 
      } 
        if ($hasError) {
            global $sc_seq_vert;
