    function ValidateField_databaixa_(&$Campos_Crit, &$Campos_Falta, &$Campos_Erros)
    {
        global $teste_validade;
        $hasError = false;
      nm_limpa_data($this->databaixa_, $this->field_config['databaixa_']['date_sep']) ; 
      if (isset($this->Field_no_validate['databaixa_'])) {
          return;
      }
      $trab_dt_min = ""; 
      $trab_dt_max = ""; 
      $trab_dt_max = date('Ymd'); 
      $trab_dt_dia = date('d'); 
      $trab_dt_mes = date('m'); 
      $trab_dt_ano = date('Y'); 
      $this->nm_data->nm_calc_data($trab_dt_dia, $trab_dt_mes, $trab_dt_ano, 0, 0, 10, "-"); 
      $trab_dt_min = $trab_dt_ano . $trab_dt_mes . $trab_dt_dia; 
      if ($this->nmgp_opcao != "excluir") 
      { 
          $guarda_datahora = $this->field_config['databaixa_']['date_format']; 
          if (false !== strpos($guarda_datahora, ';')) $this->field_config['databaixa_']['date_format'] = substr($guarda_datahora, 0, strpos($guarda_datahora, ';'));
          $Format_Data = $this->field_config['databaixa_']['date_format']; 
          nm_limpa_data($Format_Data, $this->field_config['databaixa_']['date_sep']) ; 
          if (trim($this->databaixa_) != "")  
          { 
              $validateTest = $teste_validade->Data($this->databaixa_, $Format_Data, $trab_dt_min, $trab_dt_max);
              if ($validateTest == false)
              { 
                  $hasError = true;
                  $Campos_Crit .= "Baixado em; " ; 
                  if (!isset($Campos_Erros['databaixa_']))
                  {
                      $Campos_Erros['databaixa_'] = array();
                  }
                  $Campos_Erros['databaixa_'][] = "" . $this->Ini->Nm_lang['lang_errm_ajax_data'] . "";
                  if (!isset($this->NM_ajax_info['errList']['databaixa_']) || !is_array($this->NM_ajax_info['errList']['databaixa_']))
                  {
                      $this->NM_ajax_info['errList']['databaixa_'] = array();
                  }
                  $this->NM_ajax_info['errList']['databaixa_'][] = "" . $this->Ini->Nm_lang['lang_errm_ajax_data'] . "";
              } 
          } 
          $this->field_config['databaixa_']['date_format'] = $guarda_datahora; 
       } 
        if ($hasError) {
            global $sc_seq_vert;
            $fieldName = 'databaixa_';
            if (isset($sc_seq_vert) && '' != $sc_seq_vert) {
                $fieldName .= $sc_seq_vert;
            }
            $this->NM_ajax_info['fieldsWithErrors'][] = $fieldName;
        }
    } // ValidateField_databaixa_

