        function initializeRecordState() {
                $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'] = array();
        }

        function storeRecordState($sc_seq_vert = 0) {
                if (!isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'])) {
                        $this->initializeRecordState();
                }
                if (!isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'][$sc_seq_vert])) {
                        $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'][$sc_seq_vert] = array();
                }

                $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'][$sc_seq_vert]['buttons'] = array(
                        'delete' => $this->nmgp_botoes['delete'],
                        'update' => $this->nmgp_botoes['update']
                );
        }

        function loadRecordState($sc_seq_vert = 0) {
                if (!isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state']) || !isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'][$sc_seq_vert])) {
                        return;
                }

                if (isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'][$sc_seq_vert]['buttons']['delete'])) {
                        $this->nmgp_botoes['delete'] = $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'][$sc_seq_vert]['buttons']['delete'];
                }
                if (isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'][$sc_seq_vert]['buttons']['update'])) {
                        $this->nmgp_botoes['update'] = $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['record_state'][$sc_seq_vert]['buttons']['update'];
                }
        }

