function AcertarPlanoConta()
{
$_SESSION['scriptcase']['LancamentoDespesa_Almoxarifado_Frm']['contr_erro'] = 'on';
  
if ($this->idtipoagente_  == 1) { 
	
	$this->idcolaborador_  = NULL;
	$this->idfornecedor_  = NULL;
	
	$this->idplanoconta_  = $this->idplanocontacliente_ ;
	$this->idplanocontacolaborador_  = NULL;
	$this->idplanocontacliente_  = NULL;
	
} elseif ($this->idtipoagente_  == 2) { 
	
	$this->idcolaborador_  = NULL;
	$this->idcliente_  = NULL;
	
	$this->idplanocontacliente_  = NULL;	
	$this->idplanocontacolaborador_  = NULL;   
	
} elseif ($this->idtipoagente_  == 3) { 
	
	$this->idfornecedor_  = NULL;
	$this->idcliente_  = NULL;
	
	$this->idplanoconta_  = $this->idplanocontacolaborador_ ;	
	$this->idplanocontacliente_  = NULL;
	
}


$_SESSION['scriptcase']['LancamentoDespesa_Almoxarifado_Frm']['contr_erro'] = 'off';
}

