/*----- Scriptcase Locale: PHP Method: AtualizarCheque ------*/

function AtualizarCheque()
{
$_SESSION['scriptcase']['LancamentoDespesa_Almoxarifado_Frm']['contr_erro'] = 'on';
if (!isset($this->sc_temp_varIdUsuario)) {$this->sc_temp_varIdUsuario = (isset($_SESSION['varIdUsuario'])) ? $_SESSION['varIdUsuario'] : "";}
  
$check_sql = "SELECT Situacao, DataSituacao, IdUsuarioSituacao, Historico"
	. " FROM cheque"
	. " WHERE IdCheque = '" . $this->idcheque_  . "'";
 
      $nm_select = $check_sql; 
      $_SESSION['scriptcase']['sc_sql_ult_comando'] = $nm_select; 
      $_SESSION['scriptcase']['sc_sql_ult_conexao'] = ''; 
      $this->rs = array();
      if ($SCrx = $this->Db->Execute($nm_select)) 
      { 
          $SCy = 0; 
          $nm_count = $SCrx->FieldCount();
          while (!$SCrx->EOF)
          { 
                 for ($SCx = 0; $SCx < $nm_count; $SCx++)
                 { 
                      $this->rs[$SCy] [$SCx] = $SCrx->fields[$SCx];
                 }
                 $SCy++; 
                 $SCrx->MoveNext();
          } 
          $SCrx->Close();
      } 
      elseif (isset($GLOBALS["NM_ERRO_IBASE"]) && $GLOBALS["NM_ERRO_IBASE"] != 1)  
      { 
          $this->rs = false;
          $this->rs_erro = $this->Db->ErrorMsg();
      } 


if (isset($this->rs[0][0])) {
   	$Situacao          = $this->rs[0][0];
   	$DataSituacao      = $this->rs[0][1];
   	$IdUsuarioSituacao = $this->rs[0][2];
   	$Historico         = $this->rs[0][3];

	$check_sql = "SELECT Nome"
		. " FROM usuario"
		. " WHERE IdUsuario = '" . $IdUsuarioSituacao . "'";
	 
      $nm_select = $check_sql; 
      $_SESSION['scriptcase']['sc_sql_ult_comando'] = $nm_select; 
      $_SESSION['scriptcase']['sc_sql_ult_conexao'] = ''; 
      $this->rs = array();
      if ($SCrx = $this->Db->Execute($nm_select)) 
      { 
          $SCy = 0; 
          $nm_count = $SCrx->FieldCount();
          while (!$SCrx->EOF)
          { 
                 for ($SCx = 0; $SCx < $nm_count; $SCx++)
                 { 
                      $this->rs[$SCy] [$SCx] = $SCrx->fields[$SCx];
                 }
                 $SCy++; 
                 $SCrx->MoveNext();
          } 
          $SCrx->Close();
      } 
      elseif (isset($GLOBALS["NM_ERRO_IBASE"]) && $GLOBALS["NM_ERRO_IBASE"] != 1)  
      { 
          $this->rs = false;
          $this->rs_erro = $this->Db->ErrorMsg();
      } 

	if (isset($this->rs[0][0])) {
   		$Nome = $this->rs[0][0];
	}
	else {
		$Nome = 'Usuário não cadastrado';
	}

	if ($Situacao == 'D') {
		$Situacao = "Disponível em ";	
	}
	elseif ($Situacao == 'E') {
		$Situacao = "Emitido em ";	
	}
	elseif ($Situacao == 'C') {
		$Situacao = "Compensado em ";	
	}
	elseif ($Situacao == 'V') {
  		$Situacao = "Devolvido em ";	
	}
	elseif ($Situacao == 'R') {
  		$Situacao = "Reapresentado em ";	
	}
	elseif ($Situacao == 'X') {
  		$Situacao = "Cancelado em ";	
	}
	elseif ($Situacao == 'S') {
  		$Situacao = "Sustado em ";	
	}
	else {
  		$Situacao = "Em ";	
	}
	
	$Historico = $Situacao . date('d/m/Y') . ' por ' . $Nome;
	$SQL = 'update cheque set Situacao = "C", Historico = concat_ws(CHAR(10), "' . $Historico . '", Historico), IdUsuarioSituacao = ' . $this->sc_temp_varIdUsuario 
		. ' where IdCheque = ' . $this->idcheque_ ;
	
     $nm_select = $SQL; 
         $_SESSION['scriptcase']['sc_sql_ult_comando'] = $nm_select;
      $_SESSION['scriptcase']['sc_sql_ult_conexao'] = ''; 
         $rf = $this->Db->Execute($nm_select);
         if ($rf === false)
         {
             $this->Erro->mensagem (__FILE__, __LINE__, "banco", $this->Ini->Nm_lang['lang_errm_dber'], $this->Db->ErrorMsg());
             $this->NM_rollback_db(); 
             if ($this->NM_ajax_flag)
             {
                LancamentoDespesa_Almoxarifado_Frm_pack_ajax_response();
             }
             exit;
         }
         $rf->Close();
      
	if ($this->Ini->sc_tem_trans_banco)
{
    $this->Db->CommitTrans();
    $this->Ini->sc_tem_trans_banco = false;
}
	
}
if (isset($this->sc_temp_varIdUsuario)) { $_SESSION['varIdUsuario'] = $this->sc_temp_varIdUsuario;}
$_SESSION['scriptcase']['LancamentoDespesa_Almoxarifado_Frm']['contr_erro'] = 'off';
}

