   function SC_fast_search($in_fields, $arg_search, $data_search)
   {
      $fields = (strpos($in_fields, "SC_all_Cmp") !== false) ? array("SC_all_Cmp") : explode(";", $in_fields);
      $this->NM_case_insensitive = true;
      if (empty($data_search)) 
      {
         unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['dyn_search_and_or']);
         unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['dyn_search_cache']);
          unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['where_filter']);
          unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['total']);
          unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['fast_search']);
          if (isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['where_detal']) && !empty($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['where_detal'])) 
          {
              $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['where_filter'] = $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['where_detal'];
          }
          if (isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['empty_filter']) && $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['empty_filter'])
          {
              unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoDespesa_Almoxarifado_Frm']['empty_filter']);
              $this->NM_ajax_info['empty_filter'] = 'ok';
              LancamentoDespesa_Almoxarifado_Frm_pack_ajax_response();
              exit;
          }
          return;
      }
      $comando = "";
      if ($_SESSION['scriptcase']['charset'] != "UTF-8" && NM_is_utf8($data_search))
      {
          $data_search = NM_conv_charset($data_search, $_SESSION['scriptcase']['charset'], "UTF-8");
      }
      $sv_data = $data_search;
      foreach ($fields as $field) {
          if ($field == "SC_all_Cmp" || $field == "idtipoagente_") 
          {
              $data_lookup = $this->SC_lookup_idtipoagente_($arg_search, $data_search);
              if (is_array($data_lookup) && !empty($data_lookup)) 
              {
                  $this->SC_monta_condicao($comando, "IdTipoAgente", $arg_search, $data_lookup, "BIGINT", false);
              }
          }
          if ($field == "SC_all_Cmp" || $field == "idfornecedor_") 
          {
              $data_lookup = $this->SC_lookup_idfornecedor_($arg_search, $data_search);
              if (is_array($data_lookup) && !empty($data_lookup)) 
              {
                  $this->SC_monta_condicao($comando, "IdFornecedor", $arg_search, $data_lookup, "BIGINT", false);
              }
          }
